import 'package:firebase_auth/firebase_auth.dart'; import 'package:injectable/injectable.dart'; import '../../../core/utils/app_logger.dart'; @singleton class TokenManager { Future<String?> getIdToken({bool forceRefresh = false}) async { try { return await FirebaseAuth.instance.currentUser?.getIdToken(forceRefresh); } catch (e) { AppLogger.error('Get ID token failed', e); return null; } } Future<void> revokeToken() async { try { await FirebaseAuth.instance.currentUser?.reload(); } catch (e) { AppLogger.warning('Token revoke: $e'); } } }